const meds = $input.first().json.body.medications;

const formatted = meds.map((med, index) => {
  const dosage = med.dosage_amount && med.dosage_unit
    ? ` ${med.dosage_amount}${med.dosage_unit}`
    : "";

  return `Medicine ${index + 1}: ${med.name}${dosage} (${med.form}) ${med.frequency}, ${med.amount_per_time} ${med.consumption_unit}`;
});

return [
  {
    json: {
      medicines_list: formatted.join(" | ")
    }
  }
];

const dob = $('Webhook').first().json.body.profile.date_of_birth;

function calculateAge(dobString) {
  const today = new Date();
  const birthDate = new Date(dobString);

  let age = today.getFullYear() - birthDate.getFullYear();

  const monthDiff = today.getMonth() - birthDate.getMonth();

  if (
    monthDiff < 0 || 
    (monthDiff === 0 && today.getDate() < birthDate.getDate())
  ) {
    age--;
  }

  return age;
}

return [
  {
    json: {
      age: calculateAge(dob)
    }
  }
];

const aiResponse = $input.first().json.output;

return [
  {
    json: {
      answer: aiResponse
    }
  }
];
